SELECT tbevSeat.SEAT_NO
  FROM TBEV_SEAT tbevSeat
 WHERE tbevSeat.SCHD_NO = #{schdNo}

SELECT tbevSeat.SEAT_NO,
       tbevSeat.SEAT_PRC
  FROM TBEV_SEAT tbevSeat
 WHERE tbevSeat.SCHD_NO = #{schdNo}
   AND tbevSeat.SEAT_NO IN

    #{seatNo}

SELECT tbpdPrd.PRD_NO,
       tbpdPrd.PRD_PRC
  FROM TBPD_PRD tbpdPrd
 WHERE tbpdPrd.SCHD_NO = #{schdNo}
   AND tbpdPrd.PRD_NO IN

    #{prdNo}
